import { Kernel } from '@semantic-kernel/core';

interface ExecutionNode {
  functionName: string;
  nextFunctions: string[];
}

function detectPlanCycles(planSteps: ExecutionNode[]): boolean {
  const visited = new Set<string>();
  const recStack = new Set<string>();

  function hasCycle(nodeName: string): boolean {
    if (recStack.has(nodeName)) return true;
    if (visited.has(nodeName)) return false;

    visited.add(nodeName);
    recStack.add(nodeName);

    for (const next of planSteps.find(s => s.functionName === nodeName)?.nextFunctions || []) {
      if (hasCycle(next)) return true;
    }

    recStack.delete(nodeName);
    return false;
  }

  return planSteps.some(step => hasCycle(step.functionName));
}
