import { ActionPlanner } from '@semantic-kernel/agents';

function validatePlan(plan: any): boolean {
  const functionCalls = new Set();
  for (const step of plan.executionGroups.flatMap((g: any) => g.functions)) {
    if (functionCalls.has(step.function.name)) {
      console.warn('CYCLE_DETECTED:', step.function.name);
      return false;
    }
    functionCalls.add(step.function.name);
  }
  return true;
}

